// Assign images: specific slug overrides take priority, then category fallback
articles.forEach((article) => {
  if (!article.image) {
    article.image = articleImages[article.slug] ?? categoryImages[article.category];
  }
});

export const getRelatedArticles = (current: Article): Article[] =>
  articles
    .filter((a) => a.category === current.category && a.slug !== current.slug)
    .slice(0, 3);
